// // This module selects between two 32-bit inputs: ALU_result and read_mem_data, based on the control signal mem_to_reg. When mem_to_reg is deasserted (0), it outputs read_mem_data; otherwise, it outputs ALU_result.
module top_module(WB_result,ALU_result,read_mem_data,mem_to_reg);output [31:0] WB_result;
input [31:0] read_mem_data;
input [31:0] ALU_result;
input mem_to_reg;

assign WB_result = mem_to_reg ? read_mem_data : ALU_result;
endmodule
